        | otherwise = RFixityDecl ((loc_1) <> (loc_4)) FF_InfixN (contents_2) (contents_3)
    getDecl (PTBranch _ [PTLeaf (T_prefix loc_1), PTLeaf (T_id loc_2 contents_2), PTLeaf (T_nat_lit loc_3 contents_3), PTLeaf (T_dot loc_4)])
        | otherwise = RFixityDecl ((loc_1) <> (loc_4)) FF_Prefix (contents_2) (contents_3)
    getDecl (PTBranch _ [PTLeaf (T_infixl loc_1), _2@(PTBranch guard2 _), PTLeaf (T_nat_lit loc_3 contents_3), PTLeaf (T_dot loc_4)])
