    getDecl (PTBranch _ [PTLeaf (T_infix loc_1), _2@(PTBranch guard2 _), PTLeaf (T_nat_lit loc_3 contents_3), PTLeaf (T_dot loc_4)])
        | [guard2] `elem` [[25]] = RFixityDecl ((loc_1) <> (loc_4)) FF_InfixN (getSymOp _2) (contents_3)
